import{_ as s,c as a,a as e,o as t}from"./app-CddT6UHG.js";const l={};function p(c,n){return t(),a("div",null,n[0]||(n[0]=[e(`<h1 id="fake-delete" tabindex="-1"><a class="header-anchor" href="#fake-delete"><span>Fake Delete</span></a></h1><p>In many applications, you want to mark entities as deleted instead of permanently removing them from the database. FluxaORM supports this pattern through fake delete (also known as soft delete).</p><h2 id="enabling-fake-delete" tabindex="-1"><a class="header-anchor" href="#enabling-fake-delete"><span>Enabling Fake Delete</span></a></h2><p>To enable fake delete on an entity, add a <code>FakeDelete bool</code> field to your entity struct:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token keyword">type</span> UserEntity <span class="token keyword">struct</span> <span class="token punctuation">{</span></span>
<span class="line">    ID         <span class="token builtin">uint64</span></span>
<span class="line">    Name       <span class="token builtin">string</span></span>
<span class="line">    Email      <span class="token builtin">string</span></span>
<span class="line">    FakeDelete <span class="token builtin">bool</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>When the schema is validated, FluxaORM automatically:</p><ol><li>Adds a <code>FakeDelete</code> column to the MySQL table (same type as the <code>bool</code> column).</li><li>Adds a <code>FakeDelete</code> index to the table.</li><li>Appends <code>FakeDelete</code> to all existing MySQL indexes (including unique indexes). This ensures that fake-deleted entities do not cause duplicate key constraint violations.</li></ol><h2 id="deleting-an-entity-soft-delete" tabindex="-1"><a class="header-anchor" href="#deleting-an-entity-soft-delete"><span>Deleting an Entity (Soft Delete)</span></a></h2><p>Call <code>Delete()</code> on an entity to mark it as fake-deleted:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">user<span class="token punctuation">,</span> found<span class="token punctuation">,</span> err <span class="token operator">:=</span> UserEntityProvider<span class="token punctuation">.</span><span class="token function">GetByID</span><span class="token punctuation">(</span>ctx<span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">)</span></span>
<span class="line">user<span class="token punctuation">.</span><span class="token function">Delete</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">err <span class="token operator">=</span> ctx<span class="token punctuation">.</span><span class="token function">Flush</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token comment">// UPDATE \`UserEntity\` SET \`FakeDelete\` = 1 WHERE \`ID\` = 3</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>The <code>Delete()</code> method sets the <code>FakeDelete</code> field to <code>true</code> and tracks the entity for flushing. The entity remains in the database -- it is simply marked as deleted.</p><p>When using <a href="/guide/lifecycle_callbacks">Lifecycle Callbacks</a>, a soft delete via <code>Delete()</code> triggers the <code>AfterDelete</code> callback, not <code>AfterUpdate</code>.</p><h2 id="permanently-deleting-an-entity" tabindex="-1"><a class="header-anchor" href="#permanently-deleting-an-entity"><span>Permanently Deleting an Entity</span></a></h2><p>Call <code>ForceDelete()</code> to permanently remove the entity from the database:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">user<span class="token punctuation">,</span> found<span class="token punctuation">,</span> err <span class="token operator">:=</span> UserEntityProvider<span class="token punctuation">.</span><span class="token function">GetByID</span><span class="token punctuation">(</span>ctx<span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">)</span></span>
<span class="line">user<span class="token punctuation">.</span><span class="token function">ForceDelete</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">err <span class="token operator">=</span> ctx<span class="token punctuation">.</span><span class="token function">Flush</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token comment">// DELETE FROM \`UserEntity\` WHERE \`ID\` = 3</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>ForceDelete()</code> bypasses the fake delete mechanism and performs a real <code>DELETE</code> statement. This is only available on entities that have the <code>FakeDelete</code> field.</p><h2 id="behavior-of-fake-deleted-entities" tabindex="-1"><a class="header-anchor" href="#behavior-of-fake-deleted-entities"><span>Behavior of Fake-Deleted Entities</span></a></h2><p>Once an entity is fake-deleted, it is <strong>excluded from search results</strong> by default. All query methods that use a <code>WHERE</code> clause automatically add <code>AND FakeDelete = 0</code> to filter out deleted rows:</p><ul><li><code>Search</code></li><li><code>SearchOne</code></li><li><code>SearchIDs</code></li><li><code>GetByIndex</code></li><li><code>GetByUniqueIndex</code></li><li><code>GetAll</code></li><li>Redis Search queries</li></ul><p>However, <code>GetByID</code> and <code>GetByIDs</code> <strong>will still return</strong> fake-deleted entities. You can check whether an entity has been fake-deleted by reading its <code>FakeDelete</code> field:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">user<span class="token punctuation">,</span> found<span class="token punctuation">,</span> err <span class="token operator">:=</span> UserEntityProvider<span class="token punctuation">.</span><span class="token function">GetByID</span><span class="token punctuation">(</span>ctx<span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">)</span> <span class="token comment">// found = true, even if fake-deleted</span></span>
<span class="line"><span class="token keyword">if</span> user<span class="token punctuation">.</span><span class="token function">GetFakeDelete</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span><span class="token string">&quot;This user has been deleted&quot;</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="including-fake-deleted-entities-in-search-results" tabindex="-1"><a class="header-anchor" href="#including-fake-deleted-entities-in-search-results"><span>Including Fake-Deleted Entities in Search Results</span></a></h2><p>If you need to include fake-deleted entities in search results, use the <code>WithFakeDeletes()</code> method on the <code>Where</code> clause:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">where <span class="token operator">:=</span> fluxaorm<span class="token punctuation">.</span><span class="token function">NewWhere</span><span class="token punctuation">(</span><span class="token string">&quot;\`Status\` = ?&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;active&quot;</span><span class="token punctuation">)</span></span>
<span class="line">where<span class="token punctuation">.</span><span class="token function">WithFakeDeletes</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">users<span class="token punctuation">,</span> err <span class="token operator">:=</span> UserEntityProvider<span class="token punctuation">.</span><span class="token function">Search</span><span class="token punctuation">(</span>ctx<span class="token punctuation">,</span> where<span class="token punctuation">,</span> fluxaorm<span class="token punctuation">.</span><span class="token function">NewPager</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">100</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token comment">// returns all matching entities, including fake-deleted ones</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Without <code>WithFakeDeletes()</code>, the same query would automatically filter out any rows where <code>FakeDelete = 1</code>.</p><h2 id="example-full-lifecycle" tabindex="-1"><a class="header-anchor" href="#example-full-lifecycle"><span>Example: Full Lifecycle</span></a></h2><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token comment">// Create a new user</span></span>
<span class="line">user <span class="token operator">:=</span> UserEntityProvider<span class="token punctuation">.</span><span class="token function">New</span><span class="token punctuation">(</span>ctx<span class="token punctuation">)</span></span>
<span class="line">user<span class="token punctuation">.</span><span class="token function">SetName</span><span class="token punctuation">(</span><span class="token string">&quot;Alice&quot;</span><span class="token punctuation">)</span></span>
<span class="line">user<span class="token punctuation">.</span><span class="token function">SetEmail</span><span class="token punctuation">(</span><span class="token string">&quot;alice@example.com&quot;</span><span class="token punctuation">)</span></span>
<span class="line">err <span class="token operator">:=</span> ctx<span class="token punctuation">.</span><span class="token function">Flush</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// Soft delete the user</span></span>
<span class="line">user<span class="token punctuation">.</span><span class="token function">Delete</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">err <span class="token operator">=</span> ctx<span class="token punctuation">.</span><span class="token function">Flush</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// The user is excluded from normal searches</span></span>
<span class="line">users<span class="token punctuation">,</span> err <span class="token operator">:=</span> UserEntityProvider<span class="token punctuation">.</span><span class="token function">Search</span><span class="token punctuation">(</span>ctx<span class="token punctuation">,</span> fluxaorm<span class="token punctuation">.</span><span class="token function">NewWhere</span><span class="token punctuation">(</span><span class="token string">&quot;1&quot;</span><span class="token punctuation">)</span><span class="token punctuation">,</span> fluxaorm<span class="token punctuation">.</span><span class="token function">NewPager</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">100</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token comment">// users does not include Alice</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// But can still be loaded by ID</span></span>
<span class="line">user<span class="token punctuation">,</span> found<span class="token punctuation">,</span> err <span class="token operator">:=</span> UserEntityProvider<span class="token punctuation">.</span><span class="token function">GetByID</span><span class="token punctuation">(</span>ctx<span class="token punctuation">,</span> user<span class="token punctuation">.</span><span class="token function">GetID</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token comment">// found = true, user.GetFakeDelete() = true</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// Include deleted users in search</span></span>
<span class="line">where <span class="token operator">:=</span> fluxaorm<span class="token punctuation">.</span><span class="token function">NewWhere</span><span class="token punctuation">(</span><span class="token string">&quot;1&quot;</span><span class="token punctuation">)</span></span>
<span class="line">where<span class="token punctuation">.</span><span class="token function">WithFakeDeletes</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">allUsers<span class="token punctuation">,</span> err <span class="token operator">:=</span> UserEntityProvider<span class="token punctuation">.</span><span class="token function">Search</span><span class="token punctuation">(</span>ctx<span class="token punctuation">,</span> where<span class="token punctuation">,</span> fluxaorm<span class="token punctuation">.</span><span class="token function">NewPager</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">100</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token comment">// allUsers includes Alice</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// Permanently remove the user</span></span>
<span class="line">user<span class="token punctuation">.</span><span class="token function">ForceDelete</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">err <span class="token operator">=</span> ctx<span class="token punctuation">.</span><span class="token function">Flush</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token comment">// The row is now deleted from the database</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,27)]))}const i=s(l,[["render",p]]),u=JSON.parse('{"path":"/guide/fake_delete.html","title":"Fake Delete","lang":"en-US","frontmatter":{},"git":{"updatedTime":1772444906000,"contributors":[{"name":"lukaszlato","username":"lukaszlato","email":"latolukasz@gmail.com","commits":3,"url":"https://github.com/lukaszlato"},{"name":"Lukasz Lato","username":"","email":"latolukasz@gmail.com","commits":2}],"changelog":[{"hash":"69544a7389a475295a69f3a8d72f70af1b3d0598","time":1772444906000,"email":"latolukasz@gmail.com","author":"Lukasz Lato","message":"Lifecycle callbacks"},{"hash":"456e3bba4fa5c1476f9974b418e090017f6b0cc2","time":1772273114000,"email":"latolukasz@gmail.com","author":"Lukasz Lato","message":"New ORM"},{"hash":"df36d23b887f15b420ad01444a0ce0929319c86f","time":1764852499000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"Context Cache"},{"hash":"bfc685f185295c4935fe51069bacb3c93ec9beda","time":1764664948000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"Context Cache"},{"hash":"2999eaa1d9039b9b2196f72bc8646d1b5b21e9b6","time":1761818175000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"Context Cache"}]},"filePathRelative":"guide/fake_delete.md"}');export{i as comp,u as data};
